import { defineConfig, loadEnv } from 'vite'
import react from '@vitejs/plugin-react'
import path from 'path'
import { fileURLToPath } from 'url'

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

// https://vitejs.dev/config/
export default defineConfig(({ mode }) => {
  const env = loadEnv(mode, process.cwd(), '');
  return {
    plugins: [react()],
    resolve: {
      alias: {
        '@': path.resolve(__dirname, './'), // Points to project root
      },
    },
    define: {
      'process.env.API_KEY': JSON.stringify(env.API_KEY || ''),
    },
    server: {
      host: true, // Listen on all local IPs
      proxy: {
        '/api': {
          target: 'http://127.0.0.1:3000', // Use IPv4 loopback to avoid "Network Error"
          changeOrigin: true,
          secure: false,
        }
      }
    }
  }
})

import axios from 'axios';

// Use relative URL. 
// In dev, Vite proxies /api to http://localhost:3000/api
// In prod, Express serves the frontend and handles /api routes on the same domain.
const client = axios.create({
  baseURL: '/api',
  headers: {
    'Content-Type': 'application/json',
  },
  timeout: 30000, // 30 second timeout
});

// Add token interceptor
client.interceptors.request.use((config) => {
  const token = localStorage.getItem('token');
  if (token) {
    config.headers.Authorization = `Bearer ${token}`;
  }
  return config;
});

// Response interceptor for auth errors
client.interceptors.response.use(
  (response) => response.data,
  (error) => {
    if (error.response?.status === 401) {
      localStorage.removeItem('token');
      window.location.href = '/'; 
    }
    // Handle Network Errors (no response received)
    if (!error.response && error.code !== 'ERR_CANCELED') {
      console.error('Network Error: Backend may be down or unreachable.', error);
    }
    return Promise.reject(error);
  }
);

