// Health Check
app.get('/health', (req, res) => {
  const dbStatus = db.open ? 'connected' : 'disconnected';
  if (db.open) {
      res.json({ status: 'ok', timestamp: new Date(), database: dbStatus });
  } else {
      res.status(503).json({ status: 'error', timestamp: new Date(), database: dbStatus });
  }
});

